// --- COMPOSANT PRINCIPAL ---

export function Skill() {
  const [selected, setSelected] = useState(0);
  const skill = SKILLS_DATA[selected];
  const count = SKILLS_DATA.length;

  return (
    <section id="skills">
      <div class="container">
        <div class="sectionLabel">02 · Stack &amp; Formation</div>
        <h2 class="sectionTitle">
          Compétences &amp; <span>Outils</span>
        </h2>
        <div class="divider"></div>

        <Reveal>
          <div class={styles.carouselWrapper} style={`--count: ${count}`}>
            {/* ── Roue ── */}
            <div class={styles.wheel}>
              {/* Anneau décoratif à l'orbite des boutons */}
              <div class={styles.orbitRing} />

              {/* Curseur doré qui tourne vers le skill actif */}
              <div class={styles.selectorRing} style={`--sel: ${selected}`} />

              {/* Boutons skill */}
              {SKILLS_DATA.map((s, i) => (
                <button
                  key={i}
                  class={`${styles.wheelBtn} ${selected === i ? styles.wheelBtnActive : ""}`}
                  style={`--i: ${i}`}
                  onClick={() => setSelected(i)}
                  title={s.title}
                  aria-label={s.title}
                >
                  <span class={styles.wheelIcon}>{s.icon}</span>
                </button>
              ))}

              {/* Centre : grande icône du skill actif */}
              <div class={styles.wheelCenter}>
                <span class={styles.wheelCenterIcon} key={selected}>
                  {skill.icon}
                </span>
              </div>
            </div>

            {/* ── Panneau détail ── */}
            <div class={styles.detail} key={selected}>
              <p class={styles.detailNumber}>
                {String(selected + 1).padStart(2, "0")} /{" "}
                {String(count).padStart(2, "0")}
              </p>
              <h3 class={styles.detailTitle}>{skill.title}</h3>
              <div class={styles.tags}>
                {skill.tags.map((tag, i) => (
                  <span
                    key={tag.name}
                    class={`${styles.tag} ${tag.highlight ? styles.hi : ""}`}
                    style={`animation-delay: ${0.08 + i * 0.06}s`}
                  >
                    {tag.name}
                  </span>
                ))}
              </div>

              {/* Dots de navigation */}
              <div class={styles.dots}>
                {SKILLS_DATA.map((_, i) => (
                  <button
                    key={i}
                    class={`${styles.dot} ${selected === i ? styles.dotActive : ""}`}
                    onClick={() => setSelected(i)}
                    aria-label={`Skill ${i + 1}`}
                  />
                ))}
              </div>
            </div>
          </div>
        </Reveal>

        <h3 class="formationTitle">Formation</h3>

        <Reveal>
          <div class={styles.diplomes}>
            {FORMATION_DATA.map((item, index) => (
              <DiplomaItem key={index} {...item} />
            ))}
          </div>
        </Reveal>
      </div>
    </section>
  );
}
